var google_play_policy_update_default = {
	"html": "<!DOCTYPE html PUBLIC \"-//W3C//DTD XHTML 1.0 Transitional//EN\" \"http://www.w3.org/TR/xhtml1/DTD/xhtml1-transitional.dtd\">\n<html lang=\"en\" dir=\"ltr\" xmlns:o=\"urn:schemas-microsoft-com:office:office\" xmlns:v=\"urn:schemas-microsoft-com:vml\">\n\n  <head>\n    <meta http-equiv=\"Content-Type\" content=\"text/html; charset=UTF-8\">\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1, user-scalable=yes\">\n    <meta name=\"x-apple-disable-message-reformatting\">\n    <meta name=\"format-detection\" content=\"telephone=no, date=no, address=no, email=no, url=no\">\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1, user-scalable=yes\">\n    <meta name=\"x-apple-disable-message-reformatting\">\n    <meta name=\"format-detection\" content=\"telephone=no, date=no, address=no, email=no, url=no\"><!--[if mso]><xml><o:OfficeDocumentSettings><o:AllowPNG /><o:PixelsPerInch>96</o:PixelsPerInch></o:OfficeDocumentSettings></xml><![endif]/-->\n  </head>\n\n  <body style=\"background-color:#dbddde;font-family:-apple-system,BlinkMacSystemFont,&#x22;Segoe UI&#x22;,Roboto,Oxygen-Sans,Ubuntu,Cantarell,&#x22;Helvetica Neue&#x22;,sans-serif\">\n    <div data-skip=\"true\" style=\"display:none;line-height:1px;max-height:0;max-width:0;opacity:0;overflow:hidden\">Google Play developers<div>\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿\xA0‌​‍‎‏﻿</div>\n    </div>\n    <div style=\"table-layout:fixed;width:100%\">\n      <div style=\"margin:0 auto;max-width:600px\"><span><!--[if mso]><table align=\"center\" width=\"600\" style=\"border-spacing: 0; width:600px;\" role=\"presentation\"><tr><td><![endif]--></span>\n        <table align=\"center\" width=\"100%\" role=\"presentation\" cellspacing=\"0\" cellpadding=\"0\" border=\"0\" style=\"max-width:600px;margin:30px auto;width:610px;background-color:#fff;border-radius:5px;overflow:hidden\">\n          <tbody>\n            <tr style=\"width:100%\">\n              <td align=\"center\">\n                <table align=\"center\" width=\"100%\" border=\"0\" cellpadding=\"0\" cellspacing=\"0\" role=\"presentation\">\n                  <tbody>\n                    <tr>\n                      <td>\n                        <table align=\"center\" width=\"100%\" role=\"presentation\" cellspacing=\"0\" cellpadding=\"0\" border=\"0\">\n                          <tbody style=\"width:100%\">\n                            <tr style=\"width:100%\">\n                              <td><img alt=\"Google Play developers header blue transparent\" src=\"https://jsx.email/assets/samples/google-play-header.png\" width=\"305\" height=\"28\" style=\"border:none;display:block;outline:none;text-decoration:none;margin-top:-1px\"><img alt=\"Google Play\" src=\"https://jsx.email/assets/samples/google-play-logo.png\" width=\"155\" height=\"31\" style=\"border:none;display:block;outline:none;text-decoration:none;padding:0 40px\"></td>\n                            </tr>\n                          </tbody>\n                        </table>\n                      </td>\n                    </tr>\n                  </tbody>\n                </table>\n                <table align=\"center\" width=\"100%\" style=\"padding:0 40px\" border=\"0\" cellpadding=\"0\" cellspacing=\"0\" role=\"presentation\">\n                  <tbody>\n                    <tr>\n                      <td>\n                        <hr style=\"border:none;border-top:1px solid #eaeaea;width:100%;border-color:#e8eaed;margin:20px 0\">\n                        <p style=\"font-size:14px;line-height:26px;margin:16px 0;font-weight:700;color:#004dcf\">DEVELOPER UPDATE</p>\n                        <p style=\"font-size:14px;line-height:22px;margin:16px 0;color:#3c4043\">Hello Google Play Developer,</p>\n                        <p style=\"font-size:14px;line-height:22px;margin:16px 0;color:#3c4043\">We strive to make Google Play a safe and trusted experience for users.</p>\n                        <p style=\"font-size:14px;line-height:22px;margin:16px 0;color:#3c4043\">We've added clarifications to our <a href=\"https://notifications.google.com\" style=\"color:#004dcf;text-decoration:none;font-size:14px;line-height:22px\">Target API Level policy</a>. Because this is a clarification, our enforcement standards and practices for this policy remain the same.</p>\n                      </td>\n                    </tr>\n                  </tbody>\n                </table>\n                <table align=\"center\" width=\"100%\" style=\"padding-left:40px\" border=\"0\" cellpadding=\"0\" cellspacing=\"0\" role=\"presentation\">\n                  <tbody>\n                    <tr>\n                      <td>\n                        <p style=\"font-size:14px;line-height:22px;margin:16px 0;color:#3c4043\">We’re noting exceptions to the <a href=\"https://notifications.google.com\" style=\"color:#004dcf;text-decoration:none;font-size:14px;line-height:22px\">Target API Level policy</a>, which can be found in our updated <a href=\"https://notifications.google.com\" style=\"color:#004dcf;text-decoration:none;font-size:14px;line-height:22px\">Help Center article.</a>These exceptions include permanently private apps and apps that target automotive or wearables form factors and are bundled within the same package. <a href=\"https://notifications.google.com\" style=\"color:#004dcf;text-decoration:none;font-size:14px;line-height:22px\">Learn more</a></p>\n                      </td>\n                    </tr>\n                  </tbody>\n                </table>\n                <table align=\"center\" width=\"100%\" style=\"padding:0 40px\" border=\"0\" cellpadding=\"0\" cellspacing=\"0\" role=\"presentation\">\n                  <tbody>\n                    <tr>\n                      <td>\n                        <p style=\"font-size:14px;line-height:22px;margin:16px 0;color:#3c4043\">We’re also extending the deadline to give you more time to adjust to these changes. Now, apps that target API level 29 or below will start experiencing reduced distribution starting <b>Jan 31, 2023</b> instead of Nov 1, 2022. If you need more time to update your app, you can request an extension to keep your app discoverable to all users until May 1, 2023.</p>\n                        <hr style=\"border:none;border-top:1px solid #eaeaea;width:100%;border-color:#e8eaed;margin:20px 0\">\n                      </td>\n                    </tr>\n                  </tbody>\n                </table>\n                <table align=\"center\" width=\"100%\" style=\"padding:0 40px\" border=\"0\" cellpadding=\"0\" cellspacing=\"0\" role=\"presentation\">\n                  <tbody>\n                    <tr>\n                      <td>\n                        <p style=\"font-size:14px;line-height:22px;margin:16px 0;color:#3c4043\">Thank you,</p>\n                        <p style=\"font-size:20px;line-height:22px;margin:16px 0;color:#3c4043\">The Google Play team</p>\n                      </td>\n                    </tr>\n                  </tbody>\n                </table>\n                <table align=\"center\" width=\"100%\" style=\"background-color:#f0fcff;width:90%;border-radius:5px;overflow:hidden;padding-left:20px\" border=\"0\" cellpadding=\"0\" cellspacing=\"0\" role=\"presentation\">\n                  <tbody>\n                    <tr>\n                      <td>\n                        <p style=\"font-size:14px;line-height:22px;margin:16px 0;color:#3c4043\">Connect with us</p>\n                        <table align=\"center\" width=\"100%\" role=\"presentation\" cellspacing=\"0\" cellpadding=\"0\" border=\"0\">\n                          <tbody style=\"width:100%\">\n                            <tr style=\"width:100%\"></tr>\n                          </tbody>\n                        </table>\n                        <table align=\"left\" width=\"100%\" style=\"width:84px;float:left\" role=\"presentation\" cellspacing=\"0\" cellpadding=\"0\" border=\"0\">\n                          <tbody style=\"width:100%\">\n                            <tr style=\"width:100%\">\n                              <td style=\"padding-right:4px\"><a href=\"https://notifications.google.com\" style=\"color:#067df7;text-decoration:none\"><img src=\"https://jsx.email/assets/samples/google-play-chat.png\" width=\"28\" height=\"28\" style=\"border:none;display:block;outline:none;text-decoration:none\"></a></td>\n                              <td style=\"padding-right:4px\"><a href=\"https://notifications.google.com\" style=\"color:#067df7;text-decoration:none\"><img src=\"https://jsx.email/assets/samples/google-play-icon.png\" width=\"28\" height=\"28\" style=\"border:none;display:block;outline:none;text-decoration:none\"></a></td>\n                              <td style=\"padding-right:4px\"><a href=\"https://notifications.google.com\" style=\"color:#067df7;text-decoration:none\"><img src=\"https://jsx.email/assets/samples/google-play-academy.png\" width=\"28\" height=\"28\" style=\"border:none;display:block;outline:none;text-decoration:none\"></a></td>\n                            </tr>\n                          </tbody>\n                        </table><img src=\"https://jsx.email/assets/samples/google-play-footer.png\" width=\"540\" height=\"48\" style=\"border:none;display:block;outline:none;text-decoration:none\">\n                        <table align=\"center\" width=\"100%\" role=\"presentation\" cellspacing=\"0\" cellpadding=\"0\" border=\"0\">\n                          <tbody style=\"width:100%\">\n                            <tr style=\"width:100%\"></tr>\n                          </tbody>\n                        </table>\n                      </td>\n                    </tr>\n                  </tbody>\n                </table>\n                <table align=\"center\" width=\"100%\" style=\"padding:0 40px;padding-bottom:30px\" border=\"0\" cellpadding=\"0\" cellspacing=\"0\" role=\"presentation\">\n                  <tbody>\n                    <tr>\n                      <td>\n                        <p style=\"font-size:12px;line-height:22px;margin:0;color:#3c4043;text-align:center\">© 2022 Google LLC 1600 Amphitheatre Parkway, Mountain View, CA 94043, USA</p>\n                        <p style=\"font-size:12px;line-height:22px;margin:0;color:#3c4043;text-align:center\">You have received this mandatory email service announcement to update you about important changes to your Google Play Developer account.</p>\n                      </td>\n                    </tr>\n                  </tbody>\n                </table>\n              </td>\n            </tr>\n          </tbody>\n        </table><span><!--[if mso]></td></tr></table><![endif]--></span>\n      </div>\n    </div>\n  </body>\n\n</html>",
	"plain": "--------------------------------------------------------------------------------\n\nDEVELOPER UPDATE\n\nHello Google Play Developer,\n\nWe strive to make Google Play a safe and trusted experience for users.\n\nWe've added clarifications to our Target API Level policy\nhttps://notifications.google.com. Because this is a clarification, our\nenforcement standards and practices for this policy remain the same.\n\nWe’re noting exceptions to the Target API Level policy\nhttps://notifications.google.com, which can be found in our updated Help Center\narticle. https://notifications.google.comThese exceptions include permanently\nprivate apps and apps that target automotive or wearables form factors and are\nbundled within the same package. Learn more https://notifications.google.com\n\nWe’re also extending the deadline to give you more time to adjust to these\nchanges. Now, apps that target API level 29 or below will start experiencing\nreduced distribution starting Jan 31, 2023 instead of Nov 1, 2022. If you need\nmore time to update your app, you can request an extension to keep your app\ndiscoverable to all users until May 1, 2023.\n\n--------------------------------------------------------------------------------\n\nThank you,\n\nThe Google Play team\n\nConnect with us\n\nhttps://notifications.google.comhttps://notifications.google.comhttps://notifications.google.com\n\n\n\n© 2022 Google LLC 1600 Amphitheatre Parkway, Mountain View, CA 94043, USA\n\nYou have received this mandatory email service announcement to update you about\nimportant changes to your Google Play Developer account.",
	"source": "import {\n  Body,\n  Container,\n  Column,\n  Head,\n  Hr,\n  Html,\n  Img,\n  Link,\n  Preview,\n  Row,\n  Section,\n  Text\n} from 'jsx-email';\n\nconst main = {\n  backgroundColor: '#dbddde',\n  fontFamily:\n    '-apple-system,BlinkMacSystemFont,\"Segoe UI\",Roboto,Oxygen-Sans,Ubuntu,Cantarell,\"Helvetica Neue\",sans-serif'\n};\n\nconst sectionLogo = {\n  padding: '0 40px'\n};\n\nconst headerBlue = {\n  marginTop: '-1px'\n};\n\nconst container = {\n  margin: '30px auto',\n  width: '610px',\n  backgroundColor: '#fff',\n  borderRadius: 5,\n  overflow: 'hidden'\n};\n\nconst containerContact = {\n  backgroundColor: '#f0fcff',\n  width: '90%',\n  borderRadius: '5px',\n  overflow: 'hidden',\n  paddingLeft: '20px'\n};\n\nconst heading = {\n  fontSize: '14px',\n  lineHeight: '26px',\n  fontWeight: '700',\n  color: '#004dcf'\n};\n\nconst paragraphContent = {\n  padding: '0 40px'\n};\n\nconst paragraphList = {\n  paddingLeft: 40\n};\n\nconst paragraph = {\n  fontSize: '14px',\n  lineHeight: '22px',\n  color: '#3c4043'\n};\n\nconst link = {\n  ...paragraph,\n  color: '#004dcf'\n};\n\nconst hr = {\n  borderColor: '#e8eaed',\n  margin: '20px 0'\n};\n\nconst baseUrl = 'https://jsx.email/assets/samples/';\n\nexport const templateName = 'Google Play Policy Update';\n\nexport const Template = () => (\n  <Html>\n    <Head />\n    <Preview>Google Play developers</Preview>\n    <Body style={main}>\n      <Container style={container}>\n        <Section>\n          <Row>\n            <Column>\n              <Img\n                style={headerBlue}\n                src={`${baseUrl}google-play-header.png`}\n                width=\"305\"\n                height=\"28\"\n                alt=\"Google Play developers header blue transparent\"\n              />\n              <Img\n                style={sectionLogo}\n                src={`${baseUrl}google-play-logo.png`}\n                width=\"155\"\n                height=\"31\"\n                alt=\"Google Play\"\n              />\n            </Column>\n          </Row>\n        </Section>\n\n        <Section style={paragraphContent}>\n          <Hr style={hr} />\n          <Text style={heading}>DEVELOPER UPDATE</Text>\n          <Text style={paragraph}>Hello Google Play Developer,</Text>\n          <Text style={paragraph}>\n            We strive to make Google Play a safe and trusted experience for users.\n          </Text>\n          <Text style={paragraph}>\n            We've added clarifications to our{' '}\n            <Link href=\"https://notifications.google.com\" style={link}>\n              Target API Level policy\n            </Link>\n            . Because this is a clarification, our enforcement standards and practices for this\n            policy remain the same.\n          </Text>\n        </Section>\n        <Section style={paragraphList}>\n          <Text style={paragraph}>\n            We’re noting exceptions to the{' '}\n            <Link href=\"https://notifications.google.com\" style={link}>\n              Target API Level policy\n            </Link>\n            , which can be found in our updated{' '}\n            <Link href=\"https://notifications.google.com\" style={link}>\n              Help Center article.\n            </Link>\n            These exceptions include permanently private apps and apps that target automotive or\n            wearables form factors and are bundled within the same package.{' '}\n            <Link href=\"https://notifications.google.com\" style={link}>\n              Learn more\n            </Link>\n          </Text>\n        </Section>\n        <Section style={paragraphContent}>\n          <Text style={paragraph}>\n            We’re also extending the deadline to give you more time to adjust to these changes. Now,\n            apps that target API level 29 or below will start experiencing reduced distribution\n            starting <b>Jan 31, 2023</b> instead of Nov 1, 2022. If you need more time to update\n            your app, you can request an extension to keep your app discoverable to all users until\n            May 1, 2023.\n          </Text>\n          <Hr style={hr} />\n        </Section>\n\n        <Section style={paragraphContent}>\n          <Text style={paragraph}>Thank you,</Text>\n          <Text style={{ ...paragraph, fontSize: '20px' }}>The Google Play team</Text>\n        </Section>\n\n        <Section style={containerContact}>\n          <Row>\n            <Text style={paragraph}>Connect with us</Text>\n          </Row>\n          <Row\n            align=\"left\"\n            style={{\n              width: '84px',\n              float: 'left'\n            }}\n          >\n            <Column style={{ paddingRight: '4px' }}>\n              <Link href=\"https://notifications.google.com\">\n                <Img width=\"28\" height=\"28\" src={`${baseUrl}google-play-chat.png`} />\n              </Link>\n            </Column>\n            <Column style={{ paddingRight: '4px' }}>\n              <Link href=\"https://notifications.google.com\">\n                <Img width=\"28\" height=\"28\" src={`${baseUrl}google-play-icon.png`} />\n              </Link>\n            </Column>\n            <Column style={{ paddingRight: '4px' }}>\n              <Link href=\"https://notifications.google.com\">\n                <Img width=\"28\" height=\"28\" src={`${baseUrl}google-play-academy.png`} />\n              </Link>\n            </Column>\n          </Row>\n          <Row>\n            <Img width=\"540\" height=\"48\" src={`${baseUrl}google-play-footer.png`} />\n          </Row>\n        </Section>\n\n        <Section style={{ ...paragraphContent, paddingBottom: 30 }}>\n          <Text\n            style={{\n              ...paragraph,\n              fontSize: '12px',\n              textAlign: 'center',\n              margin: 0\n            }}\n          >\n            © 2022 Google LLC 1600 Amphitheatre Parkway, Mountain View, CA 94043, USA\n          </Text>\n          <Text\n            style={{\n              ...paragraph,\n              fontSize: '12px',\n              textAlign: 'center',\n              margin: 0\n            }}\n          >\n            You have received this mandatory email service announcement to update you about\n            important changes to your Google Play Developer account.\n          </Text>\n        </Section>\n      </Container>\n    </Body>\n  </Html>\n);\n",
	"sourceFile": "../samples/emails/google-play-policy-update.tsx",
	"sourcePath": "/Users/powella/code/jsx-email/apps/samples/emails/google-play-policy-update.tsx",
	"templateName": "Google Play Policy Update"
};
