	"html": "<!DOCTYPE html PUBLIC \"-//W3C//DTD XHTML 1.0 Transitional//EN\" \"http://www.w3.org/TR/xhtml1/DTD/xhtml1-transitional.dtd\">\n<html lang=\"en\" dir=\"ltr\" xmlns:o=\"urn:schemas-microsoft-com:office:office\" xmlns:v=\"urn:schemas-microsoft-com:vml\">\n\n  <head>\n    <meta http-equiv=\"Content-Type\" content=\"text/html; charset=UTF-8\">\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1, user-scalable=yes\">\n    <meta name=\"x-apple-disable-message-reformatting\">\n    <meta name=\"format-detection\" content=\"telephone=no, date=no, address=no, email=no, url=no\">\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1, user-scalable=yes\">\n    <meta name=\"x-apple-disable-message-reformatting\">\n    <meta name=\"format-detection\" content=\"telephone=no, date=no, address=no, email=no, url=no\"><!--[if mso]><xml><o:OfficeDocumentSettings><o:AllowPNG /><o:PixelsPerInch>96</o:PixelsPerInch></o:OfficeDocumentSettings></xml><![endif]/-->\n  </head>\n\n  <body style=\"background-color:#ffffff;font-family:HelveticaNeue,Helvetica,Arial,sans-serif\">\n    <div style=\"table-layout:fixed;width:100%\">\n      <div style=\"margin:0 auto;max-width:600px\"><span><!--[if mso]><table align=\"center\" width=\"600\" style=\"border-spacing: 0; width:600px;\" role=\"presentation\"><tr><td><![endif]--></span>\n        <table align=\"center\" width=\"100%\" role=\"presentation\" cellspacing=\"0\" cellpadding=\"0\" border=\"0\" style=\"max-width:600px;background-color:#ffffff;border:1px solid #eee;border-radius:5px;box-shadow:0 5px 10px rgba(20,50,70,.2);margin-top:20px;width:360px;margin:0 auto;padding:68px 0 130px\">\n          <tbody>\n            <tr style=\"width:100%\">\n              <td align=\"center\"><img alt=\"Plaid\" src=\"https://jsx.email/assets/samples/plaid-logo.png\" width=\"212\" height=\"88\" style=\"border:none;display:block;outline:none;text-decoration:none;margin:0 auto\">\n                <p style=\"font-size:11px;line-height:16px;margin:16px 8px 8px 8px;color:#0a85ea;font-weight:700;font-family:HelveticaNeue,Helvetica,Arial,sans-serif;height:16px;letter-spacing:0;text-transform:uppercase;text-align:center\">Verify Your Identity</p>\n                <h1 style=\"color:#000;display:inline-block;font-family:HelveticaNeue-Medium,Helvetica,Arial,sans-serif;font-size:20px;font-weight:500;line-height:24px;margin-bottom:0;margin-top:0;text-align:center\">Enter the following code to finish linking Venmo.</h1>\n                <table align=\"center\" width=\"100%\" style=\"background:rgba(0,0,0,.05);border-radius:4px;margin:16px auto 14px;vertical-align:middle;width:280px\" border=\"0\" cellpadding=\"0\" cellspacing=\"0\" role=\"presentation\">\n                  <tbody>\n                    <tr>\n                      <td>\n                        <p style=\"font-size:32px;line-height:40px;margin:0 auto;color:#000;display:inline-block;font-family:HelveticaNeue-Bold;font-weight:700;letter-spacing:6px;padding-bottom:8px;padding-top:8px;width:100%;text-align:center\">144833</p>\n                      </td>\n                    </tr>\n                  </tbody>\n                </table>\n                <p style=\"font-size:15px;line-height:23px;margin:0;color:#444;font-family:HelveticaNeue,Helvetica,Arial,sans-serif;letter-spacing:0;padding:0 40px;text-align:center\">Not expecting this email?</p>\n                <p style=\"font-size:15px;line-height:23px;margin:0;color:#444;font-family:HelveticaNeue,Helvetica,Arial,sans-serif;letter-spacing:0;padding:0 40px;text-align:center\">Contact <a href=\"mailto:login@plaid.com\" style=\"color:#444;text-decoration:underline\">login@plaid.com</a> if you did not request this code.</p>\n              </td>\n            </tr>\n          </tbody>\n        </table><span><!--[if mso]></td></tr></table><![endif]--></span>\n      </div>\n    </div>\n    <p style=\"font-size:12px;line-height:23px;margin:0;color:#000;font-weight:800;letter-spacing:0;margin-top:20px;font-family:HelveticaNeue,Helvetica,Arial,sans-serif;text-align:center;text-transform:uppercase\">Securely powered by Plaid.</p>\n  </body>\n\n</html>",
	"plain": "Verify Your Identity\n\n\nENTER THE FOLLOWING CODE TO FINISH LINKING VENMO.\n\n144833\n\nNot expecting this email?\n\nContact login@plaid.com login@plaid.com if you did not request this code.\n\nSecurely powered by Plaid.",
	"source": "import { Body, Container, Head, Heading, Html, Img, Link, Section, Text } from 'jsx-email';\n\ninterface PlaidVerifyIdentityEmailProps {\n  validationCode?: string;\n}\n\nconst main = {\n  backgroundColor: '#ffffff',\n  fontFamily: 'HelveticaNeue,Helvetica,Arial,sans-serif'\n};\n\nconst container = {\n  backgroundColor: '#ffffff',\n  border: '1px solid #eee',\n  borderRadius: '5px',\n  boxShadow: '0 5px 10px rgba(20,50,70,.2)',\n  marginTop: '20px',\n  width: '360px',\n  margin: '0 auto',\n  padding: '68px 0 130px'\n};\n\nconst logo = {\n  margin: '0 auto'\n};\n\nconst tertiary = {\n  color: '#0a85ea',\n  fontSize: '11px',\n  fontWeight: 700,\n  fontFamily: 'HelveticaNeue,Helvetica,Arial,sans-serif',\n  height: '16px',\n  letterSpacing: '0',\n  lineHeight: '16px',\n  margin: '16px 8px 8px 8px',\n  textTransform: 'uppercase' as const,\n  textAlign: 'center' as const\n};\n\nconst secondary = {\n  color: '#000',\n  display: 'inline-block',\n  fontFamily: 'HelveticaNeue-Medium,Helvetica,Arial,sans-serif',\n  fontSize: '20px',\n  fontWeight: 500,\n  lineHeight: '24px',\n  marginBottom: '0',\n  marginTop: '0',\n  textAlign: 'center' as const\n};\n\nconst codeContainer = {\n  background: 'rgba(0,0,0,.05)',\n  borderRadius: '4px',\n  margin: '16px auto 14px',\n  verticalAlign: 'middle',\n  width: '280px'\n};\n\nconst code = {\n  color: '#000',\n  display: 'inline-block',\n  fontFamily: 'HelveticaNeue-Bold',\n  fontSize: '32px',\n  fontWeight: 700,\n  letterSpacing: '6px',\n  lineHeight: '40px',\n  paddingBottom: '8px',\n  paddingTop: '8px',\n  margin: '0 auto',\n  width: '100%',\n  textAlign: 'center' as const\n};\n\nconst paragraph = {\n  color: '#444',\n  fontSize: '15px',\n  fontFamily: 'HelveticaNeue,Helvetica,Arial,sans-serif',\n  letterSpacing: '0',\n  lineHeight: '23px',\n  padding: '0 40px',\n  margin: '0',\n  textAlign: 'center' as const\n};\n\nconst link = {\n  color: '#444',\n  textDecoration: 'underline'\n};\n\nconst footer = {\n  color: '#000',\n  fontSize: '12px',\n  fontWeight: 800,\n  letterSpacing: '0',\n  lineHeight: '23px',\n  margin: '0',\n  marginTop: '20px',\n  fontFamily: 'HelveticaNeue,Helvetica,Arial,sans-serif',\n  textAlign: 'center' as const,\n  textTransform: 'uppercase' as const\n};\n\nconst baseUrl = 'https://jsx.email/assets/samples/';\n\nexport const previewProps = {\n  validationCode: '144833'\n} as PlaidVerifyIdentityEmailProps;\n\nexport const templateName = 'Plaid Verify Identity';\n\nexport const Template = ({ validationCode }: PlaidVerifyIdentityEmailProps) => (\n  <Html>\n    <Head />\n    <Body style={main}>\n      <Container style={container}>\n        <Img src={`${baseUrl}plaid-logo.png`} width=\"212\" height=\"88\" alt=\"Plaid\" style={logo} />\n        <Text style={tertiary}>Verify Your Identity</Text>\n        <Heading style={secondary}>Enter the following code to finish linking Venmo.</Heading>\n        <Section style={codeContainer}>\n          <Text style={code}>{validationCode}</Text>\n        </Section>\n        <Text style={paragraph}>Not expecting this email?</Text>\n        <Text style={paragraph}>\n          Contact{' '}\n          <Link href=\"mailto:login@plaid.com\" style={link}>\n            login@plaid.com\n          </Link>{' '}\n          if you did not request this code.\n        </Text>\n      </Container>\n      <Text style={footer}>Securely powered by Plaid.</Text>\n    </Body>\n  </Html>\n);\n",
	"sourceFile": "../samples/emails/plaid-verify-identity.tsx",
